var e={tag:"i18n-key-editor-tips",template:'<details class="i18n-key-editor-tips"><summary>💡 AST Format Tips</summary><ul><li><strong>Simple variable:</strong> <code>{"var": "username"}</code></li><li><strong>Formatted variable:</strong> <code>{"var": "price", "format": "currency:USD"}</code></li><li><strong>Plural forms:</strong> <code>{"var": "count", "format": "plural", "options": {"=0": "no items", "one": "1 item", "other": "\\{\\{count\\}\\} items"}}</code></li><li><strong>Select/Switch:</strong> <code>{"var": "gender", "format": "select", "options": {"male": "He", "female": "She", "other": "They"}}</code></li><li><strong>Array format:</strong> <code>["You have ", {"var": "count"}, " items"]</code></li><li><strong>String-only options:</strong> Options in plural/select must be strings with \\{\\{variable\\}\\} interpolation</li></ul></details>'};export{e as default};
